window.__QUIZ_DATA__=[{"id":"objective>Geography>2017>1","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IREWA DISTRICT and also use it to answer questions 1 to 10    The scale of the map in representative fraction (RF) is","images":["data:image/png;base64,"],"options":{"A":"1:25,000","B":"1:50,000","C":"1:150,000","D":"1:250,000"},"answer":"B","explanation":"The scale of the map in representative fraction (R.F) is 1:50,000.  It should be noted that 2cm on the map is equivalent to 1km on the ground.   Itimpliesthattheratiois2cm1km=2.021000m=2x10-2103  \u21d22x10-2103=0.02:1000=2:100,000=1:50,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>2","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The crowfly distance from Doba to Sasi is approximately","images":["data:image/png;base64,"],"options":{"A":"7.5 km","B":"6.0 km","C":"5.5 km","D":"4.5 km"},"answer":"A","explanation":"The crowfly distance from Doba to Sasi is approximately 7.5km. It should be noted the distance (in cm) from Doba to Sasi is 15cm.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>3","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the direction of IREWA from Oki?","images":["data:image/png;base64,"],"options":{"A":"North-east","B":"North","C":"South","D":"South-east"},"answer":"D","explanation":"Irewa is located along the south-eastern part of Oki.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>4","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The symbol A  950  to the north-east of IREWA is","images":["data:image/png;base64,"],"options":{"A":"bench mark","B":"spot light","C":"beacon","D":"trigonometrical station"},"answer":"D","explanation":"The symbol \u2206 950, to the north-east of IREWA is trigonometrical station.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>5","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The feature marked H on the map can best be described as a","images":["data:image/png;base64,"],"options":{"A":"plateau","B":"conical hill","C":"scarp","D":"ridge"},"answer":"D","explanation":"The feature marked H on the north-east of IREWA is trigonometrical station","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>6","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Which of the following settlements is located in the highest altitude?","images":["data:image/png;base64,"],"options":{"A":"Doba","B":"Duba","C":"Sasi","D":"Oki"},"answer":"D","explanation":"Oki is located at the highest altitude (height). Others are not.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>7","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The most likely occupation of the people of Oki is","images":["data:image/png;base64,"],"options":{"A":"fishing","B":"mining","C":"farming","D":"lumbering"},"answer":"C","explanation":"In Oki, there is abundance of scattered vegetation, there occupation is most likely to be farming.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>8","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following best explains the growth of IREWA?","images":["data:image/png;base64,"],"options":{"A":"Nodal town","B":"Centre of plantation agriculture","C":"Good climate","D":"Industrial town"},"answer":"A","explanation":"Irewa is a nodal town, i.e. it is a central settlement which links to other settlements.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>9","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The most probable reasons for the construction of the road from IREWA through Sasi to the plantation is","images":["data:image/png;base64,"],"options":{"A":"because a large percentage of the population lives in Sasi","B":"to provide a means of transporting fish from Sasi to IREWA","C":"to carry the farmers from Sasi to IREWA","D":"to evacuate farm products from the plantation to the market at IREWA"},"answer":"C","explanation":"The most probable reason for the construction of the road from IREWA through Sasi to the plantation is to carry the farmers from Sasi to IREWA.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>10","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Which of the following towns may not be visible from the feature market H?","images":[],"options":{"A":"Sasi","B":"Doba","C":"Duba","D":"Old"},"answer":"D","explanation":"Oki may not be visible from the feature marked H due to its altitude (height)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>11","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Which of the following methods of representing statistical data would be most suitable for showing annual production of rice for a country on a month-to-month basis?","images":[],"options":{"A":"Line graph","B":"Pie chart","C":"Bar graph","D":"Flow chart"},"answer":"C","explanation":"bar graph is the methods representing statistical data showing annual production of commodity or goods for the country on a mouth - mouth basics.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>12","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Which of the following type of bar graphs shows increases and decreases compared with a given average?","images":[],"options":{"A":"Divided bar graph","B":"Group bar graph","C":"Divergent bar graph","D":"Percentage bar graph"},"answer":"A","explanation":"Divided bar graph shows increase and decrease comparing to a given average.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>13","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Simple bar graph can most suitably be used to represent all the following except","images":[],"options":{"A":"Value of a country's leading exports and imports","B":"distribution of population in a country","C":"month by month rainfall records of towns","D":"values of various foodstuffs produced in a country"},"answer":"A","explanation":"Simple bar graph cannot be used in evaluating the value of a country's leading export and imports.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>14","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The temperature of the environment changes with","images":[],"options":{"A":"erosion","B":"altitude","C":"mass wasting","D":"longitude"},"answer":"B","explanation":"The temperature of the environment change with increase and decrease in Altitude (when means high above the sea level, and the pressure reduces.)","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>15","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The degree of longitude through which the earth spins within 3 hours is","images":[],"options":{"A":"15o","B":"30o","C":"45o","D":"60o"},"answer":"C","explanation":"1o \u2192 4 minutes 1 hr \u2192 60 minutes   xo \u2192 3 hours x 60 minutes  3hours \u2192 x  xo \u2192 180 minutes   x = 180 minutes   xo = 45 x 1o  xo = 45o","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>16","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"An example of physical weathering process is","images":[],"options":{"A":"carbonation","B":"exfoliation","C":"hydration","D":"hydrolysis"},"answer":"B","explanation":"Physical weathering, also known as mechanical weathering, involves the breakdown of rocks and soils through direct contact with atmospheric conditions, such as heat, water, ice and pressure. Exfoliation is a type of physical weathering where the outer layers of rock peel off in layers. The other options listed are examples of chemical weathering, which involves the change in the composition of rocks and minerals due to reactions between them and the environment.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>17","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following rocks is sedimentary?","images":[],"options":{"A":"Coal","B":"Gnesis","C":"Granite","D":"Marble"},"answer":"A","explanation":"Sedimentary rocks are types of rock that are formed by the deposition and subsequent cementation of that material at the earth surface. Example: Coal.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>18","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Granite rocks contain","images":[],"options":{"A":"silica and aluminium","B":"silica and iron","C":"magnesium and copper","D":"copper and bauxite"},"answer":"B","explanation":"Granite Rocks contain Silica and Iron. Granite rocks contain silica (SiO\u2082), but the amount of iron (Fe) in granite is generally low compared to silica.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>19","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Chemical weathering can take place most effectively when the conditions are","images":[],"options":{"A":"cold and dry","B":"hot and wet","C":"cold and wet","D":"hot and dry"},"answer":"B","explanation":"Chemical weathering is the process of breaking down rocks using chemical reactions. It is most effective in hot and wet conditions. This is because heat speeds up chemical reactions, and water is often a necessary component of these reactions. Therefore, the correct answer is 'hot and wet'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>20","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The temperature at the foot of a mountain is 20oC. If the mountain is 6,000 metres above sea level, what will be the approximate temperature at the top of the mountain? `","images":[],"options":{"A":"-19.0oC","B":"-16oC","C":"14oC","D":"19.0oC"},"answer":"A","explanation":"The temperature decreases with altitude at a rate of approximately 6.5 degrees Celsius per 1000 meters. This is known as the lapse rate. Therefore, for a mountain that is 6000 meters high, the temperature decrease would be 6.5 * 6 = 39 degrees Celsius. If the temperature at the foot of the mountain is 20 degrees Celsius, then the temperature at the top of the mountain would be 20 - 39 = -19 degrees Celsius. Therefore, the correct answer is '-19.0oC'.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>21","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The planet which revolves revolves around the sun in a clockwise direction is","images":[],"options":{"A":"jupiter","B":"mars","C":"saturn","D":"uranus"},"answer":"D","explanation":"Most planets in our solar system revolve around the sun in a counter-clockwise direction. However, Venus and Uranus are exceptions to this rule and revolve in a clockwise direction. This is known as retrograde rotation. Therefore, the correct answer is 'uranus'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>22","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Under the Greek system of climatic classification, the world is divided into","images":[],"options":{"A":"hot, temperate and dry zones","B":"torrid, equatorial and dry zones","C":"temperate, fri and hot zones","D":"torrid, temperate and frigid zones"},"answer":"D","explanation":"The world is divided into torrid, temperate and frigid zones under the greek system of climate classification.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>23","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"\"It is a pinnacle of calcium that grows from the floor of limestone cave\". This is a discription of","images":[],"options":{"A":"clint","B":"stalagmite","C":"stalactite","D":"stump"},"answer":"B","explanation":"Stalagmite is a pinnacle of calcium that grows from the top downward in the limestone carve while Stalagmite is a pinnacle of Calcium that grows from the floor of limestone cave.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>24","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is the shape of the Earth?","images":[],"options":{"A":"Geoid","B":"Eclipse","C":"Round","D":"Cuboid"},"answer":"A","explanation":"The shape of the Earth is best described as a geoid. This term comes from the Greek word 'geo', meaning Earth, and 'eidos', meaning shape. A geoid is a shape that the ocean surface would take under the influence of the gravity and rotation of Earth alone, if other influences such as winds and tides were absent. This surface is extended through the continents. The Earth is not a perfect sphere because it is slightly flattened at the poles and slightly bulging at the equator.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>25","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following processes is associated with the ejection of magma and other related materials from deep below the Earth's surface?","images":[],"options":{"A":"Folding","B":"Sedimentation","C":"Metamorphism","D":"Vulcanicity"},"answer":"D","explanation":"Vulcanicity is the process in which there is an ejection of magma and other related materials from deep below the Earth onto the Earth's surface.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>26","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following features is of volcanic origin?","images":[],"options":{"A":"Still","B":"Zeugen","C":"Loess","D":"Gorge"},"answer":"A","explanation":"Sill is a part or features of volcanic origin. Others are not.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>27","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The steep-sided flat-floored valley in hot deserts through which occasional flash floods flow is known as","images":[],"options":{"A":"bajada","B":"headland","C":"playa","D":"wadi"},"answer":"D","explanation":"A steep-sided flat-floored valley in hot deserts through which occasional flash floods flow is known as a Wadi. A Bajada is a broad slope of alluvial material at the foot of an escarpment or mountain. A Headland is a point of land, usually high and with a sheer drop, extending out into a body of water. A Playa is a flat, dried up desert basin with a hard, dry, salt-rich surface.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>28","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Rocks in the inner core of the Earth are rich in","images":[],"options":{"A":"iron and nicket","B":"nicket and magnesium","C":"lead and iron","D":"nickel and lead"},"answer":"A","explanation":"The inner core of the Earth is primarily composed of iron and nickel. The inner core is the hottest part of the Earth, and has temperatures between 4000 - 5700\u00b0C. The pressure conditions in the inner core cause the metals to be in a solid state.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>29","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following conditions occurs during equinox?","images":[],"options":{"A":"The tropic of Cancer experiences longer day than the tropic of Capricon","B":"All places across the globe experience equal lengths of day and nights","C":"They length of day at the Equator is shorter the tropic of Cancer","D":"The moon is star-shaped all through the night all over the world"},"answer":"B","explanation":"Equinox is the occurrence in which all places across the globe experience Equal length of day and night.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>30","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The sea water thrown up the beaches by the breaking waves is called","images":[],"options":{"A":"backwash","B":"underlow","C":"swash","D":"shore"},"answer":"A","explanation":"Breaking wares occur anywhere that the Amplitude is sufficient including the mid-ocean. And back wash is when the sea throw up the beaches.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>31","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which type of rainfall occurs when two air masses of different temperature and other physical properties meet?","images":[],"options":{"A":"Orographic","B":"Relief","C":"Cyclonic","D":"Convectional"},"answer":"C","explanation":"Cyclonic Rainfall occurs when two air masses of different temperature and other physical properties meets.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>32","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Two X and Y are situated on the Equator. If town X is on the Greenwich Meridian and town Y is on longitude 45o E, what will be the time of town Y, if the time at town X is 4.00 pm?","images":[],"options":{"A":"3.00 pm","B":"5.00 pm","C":"6.00 pm","D":"7.00 pm"},"answer":"D","explanation":"Note that the longitudinal difference is 45\u00b0  Recall: 15 \u00b0 = 1 hour    Therefore 45\u00b0 = 3 hours  It should be noted that the time at Y will be ahead of X since Y is located at the East.   Hence we are going to add in this case, 4 + 3 = 7.00 pm","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>33","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Mountain of denudation is another term for","images":[],"options":{"A":"volcanic mountain","B":"fold mountain","C":"block mountain","D":"residual mountain"},"answer":"D","explanation":"Denudation is an erosive process of breaking and removing the rocks from the surface of the earth. Either by weathering, erosion, moving water, which it maintain is called the residual mountain.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>34","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"When the moon comes in between the Earth and the sun in a perfect straight line, which of the following eclipse occurs?","images":[],"options":{"A":"Partial","B":"Full","C":"Solar","D":"Lunar"},"answer":"C","explanation":"Solar Eclipse occur when the moon comes in between the earth and the sun in a perfect straight line.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>35","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following desert landforms is associated with wind deposition?","images":[],"options":{"A":"Butte","B":"Yardang","C":"Wadi","D":"Barchan"},"answer":"D","explanation":"A Barchan is a crescent-shaped dune that forms under wind that blows from one direction. This is a type of landform associated with wind deposition. Wind deposition is a geological process where particles of rock are transported by the wind and then deposited in a new location.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>36","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Factors which influences the practice of irrigation include all except","images":[],"options":{"A":"Unreliable rainfall","B":"High rainfall","C":"need for more food","D":"presence of fertile soil"},"answer":"A","explanation":"Irrigation is the application of controlled amount of water to the plants at needed intervals in which unreliable rainfall cannot influence the practice of irrigation.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>37","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is a service industry?","images":[],"options":{"A":"Banking industry","B":"Food processing plant","C":"Cement factory","D":"Pharmaceutical industry"},"answer":"A","explanation":"A service industry is one that provides services rather than producing goods. The banking industry is a perfect example of a service industry because it provides financial services to its customers, such as loans, deposits, and investment products. It does not produce physical goods.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>38","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"A negative effect of mineral exploitation is","images":[],"options":{"A":"afforestation","B":"hydration","C":"pollution","D":"oxidation"},"answer":"C","explanation":"Mineral exploitation often leads to environmental degradation, including pollution. This can occur through various means such as the release of harmful substances during mining processes, degradation of land, and contamination of water sources. Afforestation, hydration, and oxidation are not negative effects of mineral exploitation.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>39","subject":"Geography","year":"2017","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"The system of agriculture which combines the growing of crops and rearing of animals is known as","images":[],"options":{"A":"diary farming","B":"mixed cropping","C":"mixed farming","D":"shifting cultivation"},"answer":"C","explanation":"Mixed farming is the system of Agriculture which combines the growing of crops and rearing of animals.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>40","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following statements is true of transhumance?","images":[],"options":{"A":"It is the seasonal migration of animal rearers in mountainous areas","B":"It is practiced by Europeans","C":"It involves the growing of specialized crops","D":"It is another name for mixed farming"},"answer":"A","explanation":"Transhumance refers to the seasonal movement of people with their livestock between fixed summer and winter pastures. In mountainous regions, this usually implies movement between higher pastures in summer and lower valleys in winter. Hence, the statement 'It is the seasonal migration of animal rearers in mountainous areas' is correct.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>41","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Most rural settlements in developing countries in Africa","images":[],"options":{"A":"are nucleated","B":"are dispersed","C":"have dense transport network","D":"have satellite towns"},"answer":"B","explanation":"Most rural settlement in developing country of africa are dispersed","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>42","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following environmental resources is non-renewable?","images":[],"options":{"A":"Rain","B":"Mineral","C":"Water","D":"Oxygen"},"answer":"B","explanation":"Environmental resources is divided into Renewable and non-renewable resources. renewable resources Examples are Rain, water, oxygen, etc.   non-renewable petroleum, minerals.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2017>43","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A town which is situated at the meeting point of roads is termed","images":[],"options":{"A":"nodal","B":"port","C":"confluence","D":"gap"},"answer":"A","explanation":"A nodal town is a term used in geography to refer to a town or city that serves as a hub or junction for various forms of transportation. It is typically located at the intersection of major roads, railways, or other transportation routes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>44","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"A major problem of air transportation in developing countries is","images":[],"options":{"A":"inadequate passengers","B":"slow speed","C":"inadequate capital","D":"inadequate space for cargo"},"answer":"C","explanation":"In developing countries, one of the major problems of air transportation is inadequate capital. This is because the establishment and maintenance of air transport infrastructure and services require a significant amount of financial resources, which many developing countries lack.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>45","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"All these factors determine what a country can produce except","images":[],"options":{"A":"size of the country","B":"technology","C":"climate","D":"natural endowment"},"answer":"A","explanation":"factor that determine what a country produce are technology, climate, natural endowment in which size of the country doesn't have effect.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>46","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following best explains the rapid urban population growth in developing countries of Africa?","images":[],"options":{"A":"Urban areas have more medical facilities","B":"Many people migrate to urban areas in search of jobs","C":"Urban areas have more living spaces","D":"There is greater security in urban areas"},"answer":"D","explanation":"The rapid urban population growth can be explained in terms that there is higher security level in the Urban region.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>47","subject":"Geography","year":"2017","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Which of the following environmental hazards is prevalent in the coastal areas?","images":[],"options":{"A":"Drought","B":"Deforestation","C":"Pollution","D":"Flooding"},"answer":"A","explanation":"Environmental hazards are occurrences that can affect the population in an environment negatively. Examples are: Drought, deforestation. Pollution, flooding, etc., in which deforestation is prevalent in Coastal area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>48","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Commodities which are used in world trade exclude","images":[],"options":{"A":"agricultural goods","B":"manufactured goods","C":"mineral resources","D":"human trafficking"},"answer":"D","explanation":"Commodities which are used in world trade are mineral resources manufactured goods, agricultural goods, etc.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2017>49","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The Rural industrial area in Germany is noted for the production of","images":[],"options":{"A":"iron and steel","B":"vehicles","C":"petroleum products","D":"copper and aluminium"},"answer":"A","explanation":"The Ruhr region in Germany is known for its iron and steel industry. It is one of the largest industrial regions in Europe and has been a major centre for coal mining, steel production and beer brewing for over a century.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2017>50","subject":"Geography","year":"2017","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following criteria is not important in distinguishing between a village and a town?","images":[],"options":{"A":"Geographical situation","B":"Population size","C":"Range of functions","D":"Variety of activities"},"answer":"A","explanation":"The geographical situation is not a distinguishing factor between a village and a town. The main differences between a village and a town are the population size, the range of functions and the variety of activities. A town is generally larger than a village and has a greater range of functions (such as administrative, commercial, and industrial activities) and a wider variety of activities.","marks":"1","difficulty":"2"}];